  'updates.101title': { de: 'Erster Patch – Höhe & Variometer', en: 'First Patch – Altitude & Variometer' },
  'updates.101desc': { de: 'Einige von euch haben Höhenprobleme gemeldet – wir haben die Ursache gefunden und innerhalb von Stunden gefixt.', en: 'Some of you reported altitude issues – we identified the cause and pushed a fix within hours.' },
  'updates.101x1': { de: '<strong>Höhenanzeige</strong> – Nur noch GPS + EGM96 statt Baro-Sensor (iOS Baro lieferte falsche Absolutwerte)', en: '<strong>Altitude display</strong> – Now uses GPS + EGM96 instead of barometric sensor (iOS barometer returned incorrect absolute values)' },
  'updates.101x2': { de: '<strong>Android Variometer</strong> – Barometer-Plugin für Variometer hinzugefügt (TYPE_PRESSURE Sensor)', en: '<strong>Android Variometer</strong> – Added barometer plugin for variometer (TYPE_PRESSURE sensor)' },
  'updates.101p1': { de: 'MSL-Höhenkorrektur für gespeicherte Trackpunkte, Marker, LogPoints, Goal Declarations', en: 'MSL altitude correction for saved track points, markers, log points, goal declarations' },
  'updates.101p2': { de: 'Hindernisse: Prefetch 3×3 Tiles beim GPS-Fix, Cache-TTL verlängert', en: 'Obstacles: prefetch 3×3 tiles on GPS fix, cache TTL extended' },
  'updates.101p3': { de: 'Ballon-Profile bleiben nach Neuinstallation erhalten (Sync Race-Condition Fix)', en: 'Balloon profiles preserved after reinstall (sync race condition fix)' },
  'updates.101p4': { de: 'PDF-Viewer: Safe Area für Notch/Dynamic Island', en: 'PDF viewer: safe area for notch/Dynamic Island' },
  'updates.101p5': { de: 'Android: Datei-Import repariert (WebChromeClient Fix)', en: 'Android: file import fixed (WebChromeClient fix)' },
  'updates.101p6': { de: 'Startplatz-Suche im Onboarding (Autocomplete statt manuelle Koordinaten)', en: 'Launch site search in onboarding (autocomplete instead of manual coordinates)' },
  'updates.101p7': { de: 'Share-Button Übersetzung korrigiert', en: 'Share button translation fixed' },
  'updates.101p8': { de: 'GPS-Vario Anzeige-Text gekürzt', en: 'GPS vario display text shortened' },

