  'updates.100title': { de: 'NTA SkyNav Beta ist live', en: 'NTA SkyNav Beta is Live' },
  'updates.100desc': { de: 'Die erste Beta-Version von NTA SkyNav ist jetzt verfügbar für <strong>Android</strong> (Google Play) und <strong>iOS</strong> (TestFlight). Danke an alle Piloten, die sich angemeldet haben – euer Feedback formt diese App.', en: 'The first beta version of NTA SkyNav is now available for <strong>Android</strong> (Google Play) and <strong>iOS</strong> (TestFlight). Thank you to all pilots who signed up – your feedback shapes this app.' },
  'updates.100f1': { de: '<strong>ICAO Karten</strong> mit Lufträumen, Hindernissen & Hochspannungsleitungen', en: '<strong>ICAO Charts</strong> with airspaces, obstacles & power lines' },
  'updates.100f2': { de: '<strong>GPS HUD</strong> – Höhe, Geschwindigkeit, Heading, Variometer', en: '<strong>GPS HUD</strong> – altitude, speed, heading, variometer' },
  'updates.100f3': { de: '<strong>Zielnavigation</strong> – Peilung, Distanz, ETA', en: '<strong>Target Navigation</strong> – bearing, distance, ETA' },
  'updates.100f4': { de: '<strong>Wetter Briefing</strong> – Wind-Layer, Temperatur, Niederschlag', en: '<strong>Weather Briefing</strong> – wind layers, temperature, precipitation' },
  'updates.100f5': { de: '<strong>Load Calculator</strong> – Hülle, Gas, Passagiere, Zuladung', en: '<strong>Load Calculator</strong> – envelope, fuel, passengers, payload' },
  'updates.100f6': { de: '<strong>Live Team Tracking</strong> – Position mit der Crew teilen', en: '<strong>Live Team Tracking</strong> – share position with your crew' },
  'updates.100f7': { de: '<strong>Digitales Logbuch</strong> – Fahrten mit GPS-Tracks aufzeichnen', en: '<strong>Digital Logbook</strong> – log flights with GPS tracks' },
  'updates.100f8': { de: '<strong>Hindernisdatenbank</strong> – Türme, Masten, Leitungen', en: '<strong>Obstacle Database</strong> – towers, masts, cables' },

